#[derive(Clone, Debug, Default, PartialEq, Eq)]
pub struct CacheStats {
    pub cache_hit_total: u64,
    pub cache_miss_total: u64,
    pub preview_hit_total: u64,
    pub preview_miss_total: u64,
    pub preview_upload_latency_ms: u128,
    pub cache_bytes: usize,
    pub texture_bytes: usize,
    pub handle_bytes: usize,
    pub eviction_count: u64,
    pub soft_pressure_total: u64,
    pub hard_pressure_total: u64,
    pub result_soft_pressure_total: u64,
    pub result_hard_pressure_total: u64,
    pub texture_soft_pressure_total: u64,
    pub texture_hard_pressure_total: u64,
    pub handle_soft_pressure_total: u64,
    pub handle_hard_pressure_total: u64,
    pub dropped_write_count: u64,
    pub release_released_total: u64,
    pub release_requeued_total: u64,
    pub release_dropped_total: u64,
    pub pending_release_count: usize,
}
